noncompliant:
bool condition = true;

for (; condition;) {  // Noncompliant - only condition is used
    // do something
    condition = someCheck();
}

for (; !done;) {     // Noncompliant
    processData();
    done = isComplete();
}

compliant:
bool condition = true;

while (condition) {  // Compliant - while loop is more readable
    // do something
    condition = someCheck();
}

while (!done) {      // Compliant
    processData();
    done = isComplete();
}

// For loop is appropriate when initialization and increment are used
for (int i = 0; i < 10; i++) {  // Compliant - proper for loop
    process(i);
}
